import { TaskPriority } from './TaskPriority.js';

/**
 * Task execution context containing timing and state information
 */
export interface TaskContext {
  /** Current high-precision timestamp */
  currentTime: number;
  /** Time when this task was scheduled to execute */
  scheduledTime: number;
  /** Delta between scheduled and actual execution time */
  timingError: number;
  /** Frame number for display-synchronized tasks */
  frameNumber: number;
  /** Whether this task is running behind schedule */
  isLate: boolean;
}

/**
 * Task execution function signature
 */
export type TaskFunction = (context: TaskContext) => Promise<void> | void;

/**
 * Task completion callback signature
 */
export type TaskCompletionCallback = (task: Task, error?: Error) => void;

/**
 * Configuration options for task creation
 */
export interface TaskOptions {
  /** Task priority level */
  priority?: TaskPriority;
  /** Maximum execution time in milliseconds */
  timeout?: number;
  /** Whether task can be interrupted by higher priority tasks */
  interruptible?: boolean;
  /** Arbitrary metadata for the task */
  metadata?: Record<string, unknown>;
  /** Completion callback */
  onComplete?: TaskCompletionCallback;
  /** Error callback */
  onError?: TaskCompletionCallback;
}

/**
 * Task execution state
 */
export enum TaskState {
  PENDING = 'pending',
  RUNNING = 'running',
  COMPLETED = 'completed',
  FAILED = 'failed',
  CANCELLED = 'cancelled'
}

/**
 * Represents a single schedulable task with timing constraints
 */
export class Task {
  private static _nextId = 0;

  public readonly id: string;
  public readonly name: string;
  public readonly priority: TaskPriority;
  public readonly timeout: number;
  public readonly interruptible: boolean;
  public readonly metadata: Record<string, unknown>;

  private _state: TaskState = TaskState.PENDING;
  private _scheduledTime: number = 0;
  private _startTime: number = 0;
  private _endTime: number = 0;
  private _error: Error | null = null;
  private _onComplete?: TaskCompletionCallback;
  private _onError?: TaskCompletionCallback;
  private _timeoutHandle: number | null = null;

  constructor(
    name: string,
    private readonly _execute: TaskFunction,
    options: TaskOptions = {}
  ) {
    this.id = `task_${++Task._nextId}`;
    this.name = name;
    this.priority = options.priority ?? TaskPriority.NORMAL;
    this.timeout = options.timeout ?? 5000; // 5 second default timeout
    this.interruptible = options.interruptible ?? true;
    this.metadata = { ...options.metadata };
    this._onComplete = options.onComplete;
    this._onError = options.onError;
  }

  /**
   * Current task state
   */
  get state(): TaskState {
    return this._state;
  }

  /**
   * Time when task was scheduled to execute
   */
  get scheduledTime(): number {
    return this._scheduledTime;
  }

  /**
   * Time when task actually started executing
   */
  get startTime(): number {
    return this._startTime;
  }

  /**
   * Time when task completed
   */
  get endTime(): number {
    return this._endTime;
  }

  /**
   * Execution duration in milliseconds
   */
  get duration(): number {
    if (this._startTime === 0) return 0;
    return (this._endTime || performance.now()) - this._startTime;
  }

  /**
   * Timing error (difference between scheduled and actual start time)
   */
  get timingError(): number {
    if (this._startTime === 0 || this._scheduledTime === 0) return 0;
    return this._startTime - this._scheduledTime;
  }

  /**
   * Error that occurred during execution (if any)
   */
  get error(): Error | null {
    return this._error;
  }

  /**
   * Whether this task is currently running
   */
  get isRunning(): boolean {
    return this._state === TaskState.RUNNING;
  }

  /**
   * Whether this task has completed (successfully or failed)
   */
  get isCompleted(): boolean {
    return this._state === TaskState.COMPLETED || 
           this._state === TaskState.FAILED || 
           this._state === TaskState.CANCELLED;
  }

  /**
   * Execute the task with timing context
   * @internal Called by the scheduler
   */
  async execute(scheduledTime: number, currentTime: number, frameNumber: number): Promise<void> {
    if (this._state !== TaskState.PENDING) {
      throw new Error(`Task ${this.id} is not in pending state`);
    }

    this._scheduledTime = scheduledTime;
    this._startTime = currentTime;
    this._state = TaskState.RUNNING;

    // Set up timeout if specified
    if (this.timeout > 0) {
      this._timeoutHandle = window.setTimeout(() => {
        this.cancel(new Error(`Task ${this.id} timed out after ${this.timeout}ms`));
      }, this.timeout);
    }

    try {
      const context: TaskContext = {
        currentTime,
        scheduledTime,
        timingError: currentTime - scheduledTime,
        frameNumber,
        isLate: currentTime > scheduledTime + 1 // Consider >1ms as late
      };

      await this._execute(context);
      this._complete();
    } catch (error) {
      this._fail(error instanceof Error ? error : new Error(String(error)));
    }
  }

  /**
   * Cancel the task
   */
  cancel(reason?: Error): void {
    if (this.isCompleted) return;

    this._state = TaskState.CANCELLED;
    this._endTime = performance.now();
    this._error = reason || new Error('Task was cancelled');

    if (this._timeoutHandle !== null) {
      clearTimeout(this._timeoutHandle);
      this._timeoutHandle = null;
    }

    this._onError?.(this, this._error);
  }

  /**
   * Mark task as completed successfully
   * @private
   */
  private _complete(): void {
    this._state = TaskState.COMPLETED;
    this._endTime = performance.now();

    if (this._timeoutHandle !== null) {
      clearTimeout(this._timeoutHandle);
      this._timeoutHandle = null;
    }

    this._onComplete?.(this);
  }

  /**
   * Mark task as failed
   * @private
   */
  private _fail(error: Error): void {
    this._state = TaskState.FAILED;
    this._endTime = performance.now();
    this._error = error;

    if (this._timeoutHandle !== null) {
      clearTimeout(this._timeoutHandle);
      this._timeoutHandle = null;
    }

    this._onError?.(this, error);
  }

  /**
   * Create a copy of this task with the same configuration
   */
  clone(newName?: string): Task {
    return new Task(newName || this.name, this._execute, {
      priority: this.priority,
      timeout: this.timeout,
      interruptible: this.interruptible,
      metadata: { ...this.metadata },
      onComplete: this._onComplete,
      onError: this._onError
    });
  }

  /**
   * String representation for debugging
   */
  toString(): string {
    return `Task(${this.id}, "${this.name}", ${TaskPriority[this.priority]}, ${this._state})`;
  }
}

