import { Task, TaskOptions } from './Task.js';
import { TaskPriority } from './TaskPriority.js';

/**
 * Timeline event representing a scheduled task
 */
export interface TimelineEvent {
  /** Unique event identifier */
  id: string;
  /** Time offset from timeline start (ms) */
  time: number;
  /** Task to execute at this time */
  task: Task;
  /** Whether this event has been executed */
  executed: boolean;
}

/**
 * Timeline execution state
 */
export enum TimelineState {
  IDLE = 'idle',
  RUNNING = 'running',
  PAUSED = 'paused',
  COMPLETED = 'completed',
  CANCELLED = 'cancelled'
}

/**
 * Timeline configuration options
 */
export interface TimelineOptions {
  /** Timeline name for debugging */
  name?: string;
  /** Whether timeline can repeat */
  repeatable?: boolean;
  /** Number of repetitions (0 = infinite) */
  repetitions?: number;
  /** Time between repetitions (ms) */
  repetitionDelay?: number;
  /** Default priority for tasks added without explicit priority */
  defaultPriority?: TaskPriority;
  /** Metadata for the timeline */
  metadata?: Record<string, unknown>;
}

/**
 * Hierarchical timeline for organizing experiment sequences
 * Supports nested timelines and precise task scheduling
 */
export class Timeline {
  private static _nextId = 0;

  public readonly id: string;
  public readonly name: string;
  public readonly repeatable: boolean;
  public readonly repetitions: number;
  public readonly repetitionDelay: number;
  public readonly defaultPriority: TaskPriority;
  public readonly metadata: Record<string, unknown>;

  private _events: TimelineEvent[] = [];
  private _children: Timeline[] = [];
  private _parent: Timeline | null = null;
  private _state: TimelineState = TimelineState.IDLE;
  private _startTime: number = 0;
  private _currentTime: number = 0;
  private _currentRepetition: number = 0;
  private _eventCallbacks: Map<string, ((event: TimelineEvent) => void)[]> = new Map();

  constructor(options: TimelineOptions = {}) {
    this.id = `timeline_${++Timeline._nextId}`;
    this.name = options.name || `Timeline ${this.id}`;
    this.repeatable = options.repeatable ?? false;
    this.repetitions = options.repetitions ?? 1;
    this.repetitionDelay = options.repetitionDelay ?? 0;
    this.defaultPriority = options.defaultPriority ?? TaskPriority.NORMAL;
    this.metadata = { ...options.metadata };
  }

  /**
   * Current timeline state
   */
  get state(): TimelineState {
    return this._state;
  }

  /**
   * Parent timeline (if this is a child timeline)
   */
  get parent(): Timeline | null {
    return this._parent;
  }

  /**
   * Child timelines
   */
  get children(): readonly Timeline[] {
    return [...this._children];
  }

  /**
   * All events in this timeline
   */
  get events(): readonly TimelineEvent[] {
    return [...this._events];
  }

  /**
   * Timeline duration (time of last event)
   */
  get duration(): number {
    if (this._events.length === 0) return 0;
    return Math.max(...this._events.map(e => e.time));
  }

  /**
   * Current execution time relative to timeline start
   */
  get currentTime(): number {
    return this._currentTime;
  }

  /**
   * Current repetition number (0-based)
   */
  get currentRepetition(): number {
    return this._currentRepetition;
  }

  /**
   * Whether timeline is currently running
   */
  get isRunning(): boolean {
    return this._state === TimelineState.RUNNING;
  }

  /**
   * Whether timeline has completed all repetitions
   */
  get isCompleted(): boolean {
    return this._state === TimelineState.COMPLETED || this._state === TimelineState.CANCELLED;
  }

  /**
   * Add a task to execute at a specific time
   */
  addTask(time: number, task: Task): TimelineEvent {
    if (this._state === TimelineState.RUNNING) {
      throw new Error('Cannot add tasks to running timeline');
    }

    const event: TimelineEvent = {
      id: `event_${this.id}_${time}_${this._events.length}`,
      time,
      task,
      executed: false
    };

    this._events.push(event);
    this._events.sort((a, b) => a.time - b.time); // Keep events sorted by time

    return event;
  }

  /**
   * Add a task using a factory function for convenience
   */
  add(time: number, name: string, execute: (context: any) => Promise<void> | void, options?: TaskOptions): TimelineEvent {
    const priority = options?.priority ?? this.defaultPriority;
    const task = new Task(name, execute, { ...options, priority });
    return this.addTask(time, task);
  }

  /**
   * Add a child timeline to execute at a specific time
   */
  addTimeline(time: number, timeline: Timeline): TimelineEvent {
    if (timeline._parent !== null) {
      throw new Error('Timeline already has a parent');
    }

    timeline._parent = this;
    this._children.push(timeline);

    // Create a task that starts the child timeline
    const task = new Task(`Start ${timeline.name}`, async () => {
      await timeline.start();
    }, { priority: this.defaultPriority });

    return this.addTask(time, task);
  }

  /**
   * Remove an event from the timeline
   */
  removeEvent(eventId: string): boolean {
    if (this._state === TimelineState.RUNNING) {
      throw new Error('Cannot remove events from running timeline');
    }

    const index = this._events.findIndex(e => e.id === eventId);
    if (index === -1) return false;

    this._events.splice(index, 1);
    return true;
  }

  /**
   * Remove a child timeline
   */
  removeTimeline(timeline: Timeline): boolean {
    const index = this._children.indexOf(timeline);
    if (index === -1) return false;

    timeline._parent = null;
    this._children.splice(index, 1);

    // Remove associated events
    this._events = this._events.filter(e => e.task.name !== `Start ${timeline.name}`);

    return true;
  }

  /**
   * Start timeline execution
   */
  async start(): Promise<void> {
    if (this._state === TimelineState.RUNNING) {
      throw new Error('Timeline is already running');
    }

    this._state = TimelineState.RUNNING;
    this._startTime = performance.now();
    this._currentTime = 0;
    this._currentRepetition = 0;

    try {
      await this._executeRepetitions();
      this._state = TimelineState.COMPLETED;
    } catch (error) {
      this._state = TimelineState.CANCELLED;
      throw error;
    }
  }

  /**
   * Pause timeline execution
   */
  pause(): void {
    if (this._state !== TimelineState.RUNNING) return;
    this._state = TimelineState.PAUSED;
  }

  /**
   * Resume paused timeline
   */
  resume(): void {
    if (this._state !== TimelineState.PAUSED) return;
    this._state = TimelineState.RUNNING;
  }

  /**
   * Stop timeline execution
   */
  stop(): void {
    this._state = TimelineState.CANCELLED;

    // Cancel any running child timelines
    for (const child of this._children) {
      if (child.isRunning) {
        child.stop();
      }
    }
  }

  /**
   * Reset timeline to initial state
   */
  reset(): void {
    if (this._state === TimelineState.RUNNING) {
      this.stop();
    }

    this._state = TimelineState.IDLE;
    this._startTime = 0;
    this._currentTime = 0;
    this._currentRepetition = 0;

    // Reset all events
    for (const event of this._events) {
      event.executed = false;
    }

    // Reset child timelines
    for (const child of this._children) {
      child.reset();
    }
  }

  /**
   * Get all tasks that should execute at the current time
   */
  getTasksAt(time: number, tolerance: number = 1): Task[] {
    return this._events
      .filter(e => !e.executed && Math.abs(e.time - time) <= tolerance)
      .map(e => e.task);
  }

  /**
   * Get next events that should execute after the given time
   */
  getNextEvents(afterTime: number, limit: number = 10): TimelineEvent[] {
    return this._events
      .filter(e => !e.executed && e.time > afterTime)
      .slice(0, limit);
  }

  /**
   * Listen for timeline events
   */
  on(event: 'start' | 'complete' | 'cancel' | 'taskExecuted', callback: (data?: any) => void): void {
    if (!this._eventCallbacks.has(event)) {
      this._eventCallbacks.set(event, []);
    }
    this._eventCallbacks.get(event)!.push(callback);
  }

  /**
   * Remove event listener
   */
  off(event: string, callback: (data?: any) => void): void {
    const callbacks = this._eventCallbacks.get(event);
    if (callbacks) {
      const index = callbacks.indexOf(callback);
      if (index !== -1) {
        callbacks.splice(index, 1);
      }
    }
  }

  /**
   * Execute all repetitions of the timeline
   * @private
   */
  private async _executeRepetitions(): Promise<void> {
    const totalRepetitions = this.repeatable ? this.repetitions : 1;

    for (this._currentRepetition = 0; this._currentRepetition < totalRepetitions; this._currentRepetition++) {
      if (this._state !== TimelineState.RUNNING) break;

      // Add delay between repetitions
      if (this._currentRepetition > 0 && this.repetitionDelay > 0) {
        await this._delay(this.repetitionDelay);
      }

      await this._executeSingleRun();

      // Reset events for next repetition
      if (this._currentRepetition < totalRepetitions - 1) {
        for (const event of this._events) {
          event.executed = false;
        }
      }
    }
  }

  /**
   * Execute a single run of the timeline
   * @private
   */
  private async _executeSingleRun(): Promise<void> {
    this._emit('start');

    while (this._state === TimelineState.RUNNING && this._events.some(e => !e.executed)) {
      this._currentTime = performance.now() - this._startTime;

      const readyEvents = this._events.filter(e => !e.executed && e.time <= this._currentTime);

      for (const event of readyEvents) {
        if (this._state !== TimelineState.RUNNING) break;

        try {
          await event.task.execute(
            this._startTime + event.time,
            performance.now(),
            Math.floor(this._currentTime / 16.67) // Approximate frame number
          );
          event.executed = true;
          this._emit('taskExecuted', event);
        } catch (error) {
          console.error(`Task ${event.task.name} failed:`, error);
          // Continue execution unless timeline is stopped
        }
      }

      // Wait for next frame
      await new Promise(resolve => requestAnimationFrame(resolve));
    }

    this._emit('complete');
  }

  /**
   * Emit timeline event
   * @private
   */
  private _emit(event: string, data?: any): void {
    const callbacks = this._eventCallbacks.get(event);
    if (callbacks) {
      for (const callback of callbacks) {
        try {
          callback(data);
        } catch (error) {
          console.error(`Error in timeline event callback:`, error);
        }
      }
    }
  }

  /**
   * Simple delay utility
   * @private
   */
  private _delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  /**
   * Create a timeline tree representation for debugging
   */
  toTree(indent: number = 0): string {
    const spaces = '  '.repeat(indent);
    let result = `${spaces}Timeline: ${this.name} (${this._state})\n`;

    for (const event of this._events) {
      const executed = event.executed ? '✓' : '○';
      result += `${spaces}  ${executed} ${event.time}ms: ${event.task.name}\n`;
    }

    for (const child of this._children) {
      result += child.toTree(indent + 1);
    }

    return result;
  }

  /**
   * String representation for debugging
   */
  toString(): string {
    return `Timeline(${this.id}, "${this.name}", ${this._events.length} events, ${this._state})`;
  }
}

