import { describe, it, expect } from 'vitest';
import { TaskPriority, TaskPriorityUtils } from '../src/TaskPriority.js';

describe('TaskPriority', () => {
  it('should have correct priority values', () => {
    expect(TaskPriority.BACKGROUND).toBe(0);
    expect(TaskPriority.NORMAL).toBe(1);
    expect(TaskPriority.HIGH).toBe(2);
    expect(TaskPriority.CRITICAL).toBe(3);
    expect(TaskPriority.REALTIME).toBe(4);
  });
});

describe('TaskPriorityUtils', () => {
  describe('compare', () => {
    it('should sort higher priorities first', () => {
      expect(TaskPriorityUtils.compare(TaskPriority.HIGH, TaskPriority.NORMAL)).toBe(-1);
      expect(TaskPriorityUtils.compare(TaskPriority.NORMAL, TaskPriority.HIGH)).toBe(1);
      expect(TaskPriorityUtils.compare(TaskPriority.HIGH, TaskPriority.HIGH)).toBe(0);
    });

    it('should handle all priority combinations correctly', () => {
      const priorities = [
        TaskPriority.BACKGROUND,
        TaskPriority.NORMAL, 
        TaskPriority.HIGH,
        TaskPriority.CRITICAL,
        TaskPriority.REALTIME
      ];

      for (let i = 0; i < priorities.length; i++) {
        for (let j = 0; j < priorities.length; j++) {
          const result = TaskPriorityUtils.compare(priorities[i]!, priorities[j]!);
          if (i < j) {
            expect(result).toBe(1); // Lower priority comes after
          } else if (i > j) {
            expect(result).toBe(-1); // Higher priority comes before
          } else {
            expect(result).toBe(0); // Same priority
          }
        }
      }
    });
  });

  describe('isCritical', () => {
    it('should identify critical priorities', () => {
      expect(TaskPriorityUtils.isCritical(TaskPriority.BACKGROUND)).toBe(false);
      expect(TaskPriorityUtils.isCritical(TaskPriority.NORMAL)).toBe(false);
      expect(TaskPriorityUtils.isCritical(TaskPriority.HIGH)).toBe(false);
      expect(TaskPriorityUtils.isCritical(TaskPriority.CRITICAL)).toBe(true);
      expect(TaskPriorityUtils.isCritical(TaskPriority.REALTIME)).toBe(true);
    });
  });

  describe('getName', () => {
    it('should return correct names for all priorities', () => {
      expect(TaskPriorityUtils.getName(TaskPriority.BACKGROUND)).toBe('BACKGROUND');
      expect(TaskPriorityUtils.getName(TaskPriority.NORMAL)).toBe('NORMAL');
      expect(TaskPriorityUtils.getName(TaskPriority.HIGH)).toBe('HIGH');
      expect(TaskPriorityUtils.getName(TaskPriority.CRITICAL)).toBe('CRITICAL');
      expect(TaskPriorityUtils.getName(TaskPriority.REALTIME)).toBe('REALTIME');
    });

    it('should handle unknown priorities', () => {
      expect(TaskPriorityUtils.getName(999 as TaskPriority)).toBe('UNKNOWN');
    });
  });
});

