} from '../src/index.js';

describe('Scheduler Package Exports', () => {
  describe('core exports', () => {
    it('should export main classes', () => {
      expect(Scheduler).toBeDefined();
      expect(Task).toBeDefined();
      expect(Timeline).toBeDefined();
      expect(TaskPriority).toBeDefined();
      expect(TaskPriorityUtils).toBeDefined();
    });

    it('should export helper functions', () => {
      expect(createScheduler).toBeTypeOf('function');
      expect(createTimeline).toBeTypeOf('function');
      expect(createTrialTimeline).toBeTypeOf('function');
      expect(createTask).toBeTypeOf('function');
      expect(createStimulusTask).toBeTypeOf('function');
      expect(createResponseTask).toBeTypeOf('function');
    });

    it('should export version', () => {
      expect(VERSION).toBe('0.1.0');
    });

    it('should export default object', () => {
      expect(SchedulerModule).toBeDefined();
      expect(SchedulerModule.Scheduler).toBe(Scheduler);
      expect(SchedulerModule.VERSION).toBe(VERSION);
    });
  });

  describe('createScheduler', () => {
    it('should create scheduler with default options', () => {
      const scheduler = createScheduler();

      expect(scheduler).toBeInstanceOf(Scheduler);
      expect(scheduler.isRunning).toBe(false);
    });

    it('should create scheduler with custom options', () => {
      const scheduler = createScheduler({
        maxTasksPerFrame: 5,
        frameTimeBudget: 16
      });

      expect(scheduler).toBeInstanceOf(Scheduler);
    });
  });

  describe('createTimeline', () => {
    it('should create timeline with name', () => {
      const timeline = createTimeline('Test Timeline');

      expect(timeline).toBeInstanceOf(Timeline);
      expect(timeline.name).toBe('Test Timeline');
      expect(timeline.repeatable).toBe(false);
      expect(timeline.repetitions).toBe(1);
    });

    it('should create timeline with custom options', () => {
      const timeline = createTimeline('Custom Timeline', {
        defaultPriority: TaskPriority.HIGH,
        metadata: { type: 'experiment' }
      });

      expect(timeline.name).toBe('Custom Timeline');
      expect(timeline.defaultPriority).toBe(TaskPriority.HIGH);
      expect(timeline.metadata).toEqual({ type: 'experiment' });
    });
  });

  describe('createTrialTimeline', () => {
    it('should create repeating timeline', () => {
      const timeline = createTrialTimeline('Trial Timeline', 10, 1000);

      expect(timeline).toBeInstanceOf(Timeline);
      expect(timeline.name).toBe('Trial Timeline');
      expect(timeline.repeatable).toBe(true);
      expect(timeline.repetitions).toBe(10);
      expect(timeline.repetitionDelay).toBe(1000);
    });

    it('should create timeline with no delay', () => {
      const timeline = createTrialTimeline('Fast Trials', 5);

      expect(timeline.repetitions).toBe(5);
      expect(timeline.repetitionDelay).toBe(0);
    });

    it('should accept additional options', () => {
      const timeline = createTrialTimeline('Custom Trials', 3, 500, {
        defaultPriority: TaskPriority.CRITICAL
      });

      expect(timeline.defaultPriority).toBe(TaskPriority.CRITICAL);
    });
  });

  describe('createTask', () => {
    it('should create task with normal priority by default', () => {
      const execute = vi.fn();
      const task = createTask('Test Task', execute);

      expect(task).toBeInstanceOf(Task);
      expect(task.name).toBe('Test Task');
      expect(task.priority).toBe(TaskPriority.NORMAL);
    });

    it('should create task with custom priority', () => {
      const execute = vi.fn();
      const task = createTask('High Priority Task', execute, TaskPriority.HIGH);

      expect(task.priority).toBe(TaskPriority.HIGH);
    });

    it('should create task with additional options', () => {
      const execute = vi.fn();
      const task = createTask('Custom Task', execute, TaskPriority.NORMAL, {
        timeout: 2000,
        interruptible: false
      });

      expect(task.timeout).toBe(2000);
      expect(task.interruptible).toBe(false);
    });
  });

  describe('createStimulusTask', () => {
    it('should create high-priority stimulus task', () => {
      const stimulusFunction = vi.fn();
      const task = createStimulusTask('Show Stimulus', stimulusFunction);

      expect(task).toBeInstanceOf(Task);
      expect(task.name).toBe('Show Stimulus');
      expect(task.priority).toBe(TaskPriority.HIGH);
      expect(task.timeout).toBe(10000);
      expect(task.interruptible).toBe(false);
    });

    it('should accept custom options', () => {
      const stimulusFunction = vi.fn();
      const task = createStimulusTask('Custom Stimulus', stimulusFunction, {
        timeout: 5000,
        metadata: { type: 'visual' }
      });

      expect(task.timeout).toBe(5000);
      expect(task.metadata).toEqual({ type: 'visual' });
      expect(task.priority).toBe(TaskPriority.HIGH); // Should not be overridden
    });
  });

  describe('createResponseTask', () => {
    it('should create critical-priority response task', () => {
      const responseFunction = vi.fn();
      const task = createResponseTask('Collect Response', responseFunction);

      expect(task).toBeInstanceOf(Task);
      expect(task.name).toBe('Collect Response');
      expect(task.priority).toBe(TaskPriority.CRITICAL);
      expect(task.timeout).toBe(5000);
      expect(task.interruptible).toBe(true);
    });

    it('should accept custom timeout', () => {
      const responseFunction = vi.fn();
      const task = createResponseTask('Quick Response', responseFunction, 2000);

      expect(task.timeout).toBe(2000);
    });

    it('should accept additional options', () => {
      const responseFunction = vi.fn();
      const task = createResponseTask('Custom Response', responseFunction, 3000, {
        metadata: { modality: 'keyboard' }
      });

      expect(task.timeout).toBe(3000);
      expect(task.metadata).toEqual({ modality: 'keyboard' });
      expect(task.priority).toBe(TaskPriority.CRITICAL); // Should not be overridden
    });
  });

  describe('integration example', () => {
    it('should work together in a complete example', () => {
      // Create scheduler
      const scheduler = createScheduler({
        maxTasksPerFrame: 5,
        timingTolerance: 1
      });

      // Create experiment timeline
      const experiment = createTimeline('Stroop Experiment');

      // Create trial timeline  
      const trials = createTrialTimeline('Stroop Trials', 20, 2000);

      // Create tasks
      const showStimulus = createStimulusTask('Show Word', vi.fn());
      const collectResponse = createResponseTask('Get Keypress', vi.fn(), 3000);
      const showFeedback = createTask('Show Feedback', vi.fn(), TaskPriority.NORMAL);

      // Add tasks to trial timeline
      trials.addTask(0, showStimulus);
      trials.addTask(100, collectResponse);
      trials.addTask(3200, showFeedback);

      // Add trials to experiment
      experiment.addTimeline(1000, trials);

      // Verify structure
      expect(scheduler).toBeInstanceOf(Scheduler);
      expect(experiment.children).toContain(trials);
      expect(trials.events).toHaveLength(3);
      expect(trials.duration).toBe(3200);
    });
  });
});

