import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { Task, TaskState, type TaskContext } from '../src/Task.js';
import { TaskPriority } from '../src/TaskPriority.js';

describe('Task', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.restoreAllTimers();
  });

  describe('constructor', () => {
    it('should create task with default options', () => {
      const execute = vi.fn();
      const task = new Task('test-task', execute);

      expect(task.name).toBe('test-task');
      expect(task.priority).toBe(TaskPriority.NORMAL);
      expect(task.timeout).toBe(5000);
      expect(task.interruptible).toBe(true);
      expect(task.state).toBe(TaskState.PENDING);
      expect(task.id).toMatch(/^task_\d+$/);
    });

    it('should create task with custom options', () => {
      const execute = vi.fn();
      const onComplete = vi.fn();
      const onError = vi.fn();

      const task = new Task('test-task', execute, {
        priority: TaskPriority.HIGH,
        timeout: 1000,
        interruptible: false,
        metadata: { type: 'stimulus' },
        onComplete,
        onError
      });

      expect(task.priority).toBe(TaskPriority.HIGH);
      expect(task.timeout).toBe(1000);
      expect(task.interruptible).toBe(false);
      expect(task.metadata).toEqual({ type: 'stimulus' });
    });

    it('should assign unique IDs', () => {
      const task1 = new Task('task1', vi.fn());
      const task2 = new Task('task2', vi.fn());

      expect(task1.id).not.toBe(task2.id);
    });
  });

  describe('state management', () => {
    it('should track state transitions correctly', () => {
      const task = new Task('test', vi.fn());

      expect(task.state).toBe(TaskState.PENDING);
      expect(task.isRunning).toBe(false);
      expect(task.isCompleted).toBe(false);
    });

    it('should update state during execution', async () => {
      let taskContext: TaskContext;
      const execute = vi.fn(async (context: TaskContext) => {
        taskContext = context;
        expect(task.state).toBe(TaskState.RUNNING);
        expect(task.isRunning).toBe(true);
      });

      const task = new Task('test', execute);
      const scheduledTime = 1000;
      const currentTime = 1002;

      await task.execute(scheduledTime, currentTime, 60);

      expect(task.state).toBe(TaskState.COMPLETED);
      expect(task.isRunning).toBe(false);
      expect(task.isCompleted).toBe(true);
      expect(task.scheduledTime).toBe(scheduledTime);
      expect(task.startTime).toBe(currentTime);
      expect(task.timingError).toBe(2);

      expect(taskContext!).toEqual({
        currentTime,
        scheduledTime,
        timingError: 2,
        frameNumber: 60,
        isLate: true
      });
    });
  });

  describe('execution', () => {
    it('should execute synchronous tasks', async () => {
      const execute = vi.fn();
      const task = new Task('test', execute);

      await task.execute(1000, 1000, 60);

      expect(execute).toHaveBeenCalledTimes(1);
      expect(task.state).toBe(TaskState.COMPLETED);
    });

    it('should execute asynchronous tasks', async () => {
      const execute = vi.fn(async () => {
        await new Promise(resolve => setTimeout(resolve, 100));
      });
      const task = new Task('test', execute);

      const executePromise = task.execute(1000, 1000, 60);
      vi.advanceTimersByTime(100);
      await executePromise;

      expect(execute).toHaveBeenCalledTimes(1);
      expect(task.state).toBe(TaskState.COMPLETED);
    });

    it('should handle execution errors', async () => {
      const error = new Error('Task failed');
      const execute = vi.fn(() => {
        throw error;
      });
      const task = new Task('test', execute);

      await task.execute(1000, 1000, 60);

      expect(task.state).toBe(TaskState.FAILED);
      expect(task.error).toBe(error);
    });

    it('should handle async execution errors', async () => {
      const error = new Error('Async task failed');
      const execute = vi.fn(async () => {
        throw error;
      });
      const task = new Task('test', execute);

      await task.execute(1000, 1000, 60);

      expect(task.state).toBe(TaskState.FAILED);
      expect(task.error).toBe(error);
    });

    it('should not execute non-pending tasks', async () => {
      const execute = vi.fn();
      const task = new Task('test', execute);

      // Complete the task
      await task.execute(1000, 1000, 60);
      expect(task.state).toBe(TaskState.COMPLETED);

      // Try to execute again
      await expect(task.execute(2000, 2000, 120)).rejects.toThrow('not in pending state');
      expect(execute).toHaveBeenCalledTimes(1);
    });
  });

  describe('timeout handling', () => {
    it('should timeout long-running tasks', async () => {
      const execute = vi.fn(async () => {
        await new Promise(resolve => setTimeout(resolve, 2000));
      });
      const task = new Task('test', execute, { timeout: 1000 });

      const executePromise = task.execute(1000, 1000, 60);

      // Advance time to trigger timeout
      vi.advanceTimersByTime(1000);
      await vi.waitFor(() => expect(task.state).toBe(TaskState.CANCELLED));

      expect(task.error?.message).toContain('timed out');
    });

    it('should clear timeout on successful completion', async () => {
      const execute = vi.fn(async () => {
        await new Promise(resolve => setTimeout(resolve, 100));
      });
      const task = new Task('test', execute, { timeout: 1000 });

      const executePromise = task.execute(1000, 1000, 60);
      vi.advanceTimersByTime(100);
      await executePromise;

      expect(task.state).toBe(TaskState.COMPLETED);

      // Advance past timeout - should not affect completed task
      vi.advanceTimersByTime(1000);
      expect(task.state).toBe(TaskState.COMPLETED);
    });

    it('should handle zero timeout (no timeout)', async () => {
      const execute = vi.fn(async () => {
        await new Promise(resolve => setTimeout(resolve, 2000));
      });
      const task = new Task('test', execute, { timeout: 0 });

      const executePromise = task.execute(1000, 1000, 60);
      vi.advanceTimersByTime(2000);
      await executePromise;

      expect(task.state).toBe(TaskState.COMPLETED);
    });
  });

  describe('cancellation', () => {
    it('should cancel pending tasks', () => {
      const task = new Task('test', vi.fn());
      const reason = new Error('Cancelled for testing');

      task.cancel(reason);

      expect(task.state).toBe(TaskState.CANCELLED);
      expect(task.error).toBe(reason);
      expect(task.isCompleted).toBe(true);
    });

    it('should cancel running tasks', async () => {
      let resolveExecution: () => void;
      const execute = vi.fn(async () => {
        await new Promise<void>(resolve => {
          resolveExecution = resolve;
        });
      });
      const task = new Task('test', execute);

      const executePromise = task.execute(1000, 1000, 60);

      // Wait for task to start running
      await vi.waitFor(() => expect(task.state).toBe(TaskState.RUNNING));

      const reason = new Error('Cancelled while running');
      task.cancel(reason);

      expect(task.state).toBe(TaskState.CANCELLED);
      expect(task.error).toBe(reason);

      // Clean up
      resolveExecution!();
      await executePromise.catch(() => {/* ignore */});
    });

    it('should not affect already completed tasks', async () => {
      const execute = vi.fn();
      const task = new Task('test', execute);

      await task.execute(1000, 1000, 60);
      expect(task.state).toBe(TaskState.COMPLETED);

      task.cancel(new Error('Should not cancel'));
      expect(task.state).toBe(TaskState.COMPLETED);
      expect(task.error).toBeNull();
    });
  });

  describe('callbacks', () => {
    it('should call completion callback on success', async () => {
      const onComplete = vi.fn();
      const execute = vi.fn();
      const task = new Task('test', execute, { onComplete });

      await task.execute(1000, 1000, 60);

      expect(onComplete).toHaveBeenCalledWith(task);
    });

    it('should call error callback on failure', async () => {
      const error = new Error('Task failed');
      const onError = vi.fn();
      const execute = vi.fn(() => { throw error; });
      const task = new Task('test', execute, { onError });

      await task.execute(1000, 1000, 60);

      expect(onError).toHaveBeenCalledWith(task, error);
    });

    it('should call error callback on cancellation', () => {
      const onError = vi.fn();
      const task = new Task('test', vi.fn(), { onError });
      const reason = new Error('Cancelled');

      task.cancel(reason);

      expect(onError).toHaveBeenCalledWith(task, reason);
    });
  });

  describe('timing metrics', () => {
    it('should calculate duration correctly', async () => {
      const execute = vi.fn(async () => {
        await new Promise(resolve => setTimeout(resolve, 100));
      });
      const task = new Task('test', execute);

      const executePromise = task.execute(1000, 1000, 60);
      vi.advanceTimersByTime(100);
      await executePromise;

      expect(task.duration).toBeGreaterThan(0);
    });

    it('should calculate timing error correctly', async () => {
      const task = new Task('test', vi.fn());

      await task.execute(1000, 1005, 60); // 5ms late

      expect(task.timingError).toBe(5);
    });

    it('should handle early execution', async () => {
      const task = new Task('test', vi.fn());

      await task.execute(1000, 995, 60); // 5ms early

      expect(task.timingError).toBe(-5);
    });
  });

  describe('cloning', () => {
    it('should create identical task copy', () => {
      const execute = vi.fn();
      const original = new Task('original', execute, {
        priority: TaskPriority.HIGH,
        timeout: 2000,
        interruptible: false,
        metadata: { type: 'test' }
      });

      const clone = original.clone();

      expect(clone.id).not.toBe(original.id);
      expect(clone.name).toBe(original.name);
      expect(clone.priority).toBe(original.priority);
      expect(clone.timeout).toBe(original.timeout);
      expect(clone.interruptible).toBe(original.interruptible);
      expect(clone.metadata).toEqual(original.metadata);
      expect(clone.state).toBe(TaskState.PENDING);
    });

    it('should create copy with new name', () => {
      const original = new Task('original', vi.fn());
      const clone = original.clone('new-name');

      expect(clone.name).toBe('new-name');
      expect(clone.id).not.toBe(original.id);
    });
  });

  describe('string representation', () => {
    it('should provide meaningful toString', () => {
      const task = new Task('test-task', vi.fn(), { priority: TaskPriority.HIGH });
      const str = task.toString();

      expect(str).toContain('test-task');
      expect(str).toContain('HIGH');
      expect(str).toContain('pending');
    });
  });
});

