import { Timeline, TimelineState } from '../src/Timeline.js';
import { Task, TaskState } from '../src/Task.js';
import { TaskPriority } from '../src/TaskPriority.js';

describe('Timeline', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.restoreAllTimers();
  });

  describe('constructor', () => {
    it('should create timeline with default options', () => {
      const timeline = new Timeline();

      expect(timeline.name).toMatch(/^Timeline timeline_\d+$/);
      expect(timeline.state).toBe(TimelineState.IDLE);
      expect(timeline.repeatable).toBe(false);
      expect(timeline.repetitions).toBe(1);
      expect(timeline.repetitionDelay).toBe(0);
      expect(timeline.defaultPriority).toBe(TaskPriority.NORMAL);
      expect(timeline.parent).toBeNull();
      expect(timeline.children).toHaveLength(0);
      expect(timeline.events).toHaveLength(0);
    });

    it('should create timeline with custom options', () => {
      const timeline = new Timeline({
        name: 'Test Timeline',
        repeatable: true,
        repetitions: 5,
        repetitionDelay: 1000,
        defaultPriority: TaskPriority.HIGH,
        metadata: { type: 'trial' }
      });

      expect(timeline.name).toBe('Test Timeline');
      expect(timeline.repeatable).toBe(true);
      expect(timeline.repetitions).toBe(5);
      expect(timeline.repetitionDelay).toBe(1000);
      expect(timeline.defaultPriority).toBe(TaskPriority.HIGH);
      expect(timeline.metadata).toEqual({ type: 'trial' });
    });
  });

  describe('task management', () => {
    it('should add tasks at specific times', () => {
      const timeline = new Timeline();
      const task = new Task('test-task', vi.fn());

      const event = timeline.addTask(1000, task);

      expect(event.time).toBe(1000);
      expect(event.task).toBe(task);
      expect(event.executed).toBe(false);
      expect(timeline.events).toHaveLength(1);
      expect(timeline.duration).toBe(1000);
    });

    it('should maintain time-ordered events', () => {
      const timeline = new Timeline();

      timeline.addTask(3000, new Task('task3', vi.fn()));
      timeline.addTask(1000, new Task('task1', vi.fn()));
      timeline.addTask(2000, new Task('task2', vi.fn()));

      const times = timeline.events.map(e => e.time);
      expect(times).toEqual([1000, 2000, 3000]);
    });

    it('should add tasks using convenience method', () => {
      const timeline = new Timeline({ defaultPriority: TaskPriority.HIGH });
      const execute = vi.fn();

      const event = timeline.add(500, 'convenience-task', execute, { timeout: 2000 });

      expect(event.time).toBe(500);
      expect(event.task.name).toBe('convenience-task');
      expect(event.task.priority).toBe(TaskPriority.HIGH);
      expect(event.task.timeout).toBe(2000);
    });

    it('should remove events', () => {
      const timeline = new Timeline();
      const event = timeline.addTask(1000, new Task('test', vi.fn()));

      const removed = timeline.removeEvent(event.id);

      expect(removed).toBe(true);
      expect(timeline.events).toHaveLength(0);
    });

    it('should not remove non-existent events', () => {
      const timeline = new Timeline();

      const removed = timeline.removeEvent('non-existent');

      expect(removed).toBe(false);
    });

    it('should prevent modifications while running', async () => {
      const timeline = new Timeline();
      const startPromise = timeline.start();

      expect(() => timeline.addTask(1000, new Task('test', vi.fn()))).toThrow('Cannot add tasks to running timeline');
      expect(() => timeline.removeEvent('any-id')).toThrow('Cannot remove events from running timeline');

      timeline.stop();
      await startPromise.catch(() => {/* ignore cancellation */});
    });
  });

  describe('hierarchy management', () => {
    it('should add child timelines', () => {
      const parent = new Timeline({ name: 'Parent' });
      const child = new Timeline({ name: 'Child' });

      const event = parent.addTimeline(1000, child);

      expect(child.parent).toBe(parent);
      expect(parent.children).toContain(child);
      expect(event.time).toBe(1000);
      expect(event.task.name).toBe('Start Child');
    });

    it('should not add timeline with existing parent', () => {
      const parent1 = new Timeline({ name: 'Parent1' });
      const parent2 = new Timeline({ name: 'Parent2' });
      const child = new Timeline({ name: 'Child' });

      parent1.addTimeline(1000, child);

      expect(() => parent2.addTimeline(2000, child)).toThrow('Timeline already has a parent');
    });

    it('should remove child timelines', () => {
      const parent = new Timeline({ name: 'Parent' });
      const child = new Timeline({ name: 'Child' });

      parent.addTimeline(1000, child);
      const removed = parent.removeTimeline(child);

      expect(removed).toBe(true);
      expect(child.parent).toBeNull();
      expect(parent.children).not.toContain(child);
      expect(parent.events).toHaveLength(0);
    });
  });

  describe('execution', () => {
    it('should execute tasks at correct times', async () => {
      const timeline = new Timeline();
      const executions: number[] = [];

      timeline.add(100, 'task1', () => executions.push(1));
      timeline.add(200, 'task2', () => executions.push(2));
      timeline.add(300, 'task3', () => executions.push(3));

      const startPromise = timeline.start();

      // Advance time gradually
      vi.advanceTimersByTime(150);
      await vi.waitFor(() => expect(executions).toContain(1));

      vi.advanceTimersByTime(100);
      await vi.waitFor(() => expect(executions).toContain(2));

      vi.advanceTimersByTime(100);
      await vi.waitFor(() => expect(executions).toContain(3));

      await startPromise;

      expect(executions).toEqual([1, 2, 3]);
      expect(timeline.state).toBe(TimelineState.COMPLETED);
    });

    it('should handle async tasks', async () => {
      const timeline = new Timeline();
      const executions: string[] = [];

      timeline.add(100, 'async-task', async () => {
        await new Promise(resolve => setTimeout(resolve, 50));
        executions.push('async-completed');
      });

      const startPromise = timeline.start();
      vi.advanceTimersByTime(200);
      await startPromise;

      expect(executions).toContain('async-completed');
    });

    it('should continue on task failures', async () => {
      const timeline = new Timeline();
      const executions: string[] = [];

      timeline.add(100, 'failing-task', () => {
        throw new Error('Task failed');
      });
      timeline.add(200, 'success-task', () => executions.push('success'));

      const startPromise = timeline.start();
      vi.advanceTimersByTime(300);
      await startPromise;

      expect(executions).toContain('success');
      expect(timeline.state).toBe(TimelineState.COMPLETED);
    });

    it('should handle repeatable timelines', async () => {
      const timeline = new Timeline({
        repeatable: true,
        repetitions: 3,
        repetitionDelay: 100
      });

      const executions: number[] = [];
      timeline.add(50, 'task', () => executions.push(executions.length + 1));

      const startPromise = timeline.start();
      vi.advanceTimersByTime(500);
      await startPromise;

      expect(executions).toHaveLength(3);
      expect(timeline.currentRepetition).toBe(2); // 0-based
    });
  });

  describe('state management', () => {
    it('should transition states correctly', async () => {
      const timeline = new Timeline();
      timeline.add(100, 'task', vi.fn());

      expect(timeline.state).toBe(TimelineState.IDLE);

      const startPromise = timeline.start();
      expect(timeline.state).toBe(TimelineState.RUNNING);
      expect(timeline.isRunning).toBe(true);

      vi.advanceTimersByTime(200);
      await startPromise;

      expect(timeline.state).toBe(TimelineState.COMPLETED);
      expect(timeline.isCompleted).toBe(true);
    });

    it('should handle pause and resume', async () => {
      const timeline = new Timeline();
      const executions: number[] = [];
      timeline.add(100, 'task', () => executions.push(Date.now()));

      timeline.start();
      expect(timeline.state).toBe(TimelineState.RUNNING);

      timeline.pause();
      expect(timeline.state).toBe(TimelineState.PAUSED);

      timeline.resume();
      expect(timeline.state).toBe(TimelineState.RUNNING);

      timeline.stop();
      expect(timeline.state).toBe(TimelineState.CANCELLED);
    });

    it('should reset to initial state', async () => {
      const timeline = new Timeline();
      timeline.add(100, 'task', vi.fn());

      const startPromise = timeline.start();
      vi.advanceTimersByTime(200);
      await startPromise;

      expect(timeline.state).toBe(TimelineState.COMPLETED);

      timeline.reset();

      expect(timeline.state).toBe(TimelineState.IDLE);
      expect(timeline.currentTime).toBe(0);
      expect(timeline.currentRepetition).toBe(0);
      expect(timeline.events.every(e => !e.executed)).toBe(true);
    });
  });

  describe('query methods', () => {
    it('should get tasks at specific time', () => {
      const timeline = new Timeline();
      const task1 = new Task('task1', vi.fn());
      const task2 = new Task('task2', vi.fn());
      const task3 = new Task('task3', vi.fn());

      timeline.addTask(1000, task1);
      timeline.addTask(1001, task2);
      timeline.addTask(2000, task3);

      const tasksAt1000 = timeline.getTasksAt(1000, 2);
      expect(tasksAt1000).toContain(task1);
      expect(tasksAt1000).toContain(task2);
      expect(tasksAt1000).not.toContain(task3);
    });

    it('should get next events', () => {
      const timeline = new Timeline();
      timeline.add(1000, 'task1', vi.fn());
      timeline.add(2000, 'task2', vi.fn());
      timeline.add(3000, 'task3', vi.fn());

      const nextEvents = timeline.getNextEvents(1500, 2);
      expect(nextEvents).toHaveLength(2);
      expect(nextEvents[0]!.task.name).toBe('task2');
      expect(nextEvents[1]!.task.name).toBe('task3');
    });
  });

  describe('event system', () => {
    it('should emit timeline events', async () => {
      const timeline = new Timeline();
      const events: string[] = [];

      timeline.on('start', () => events.push('start'));
      timeline.on('complete', () => events.push('complete'));
      timeline.on('taskExecuted', () => events.push('taskExecuted'));

      timeline.add(100, 'task', vi.fn());

      const startPromise = timeline.start();
      vi.advanceTimersByTime(200);
      await startPromise;

      expect(events).toContain('start');
      expect(events).toContain('taskExecuted');
      expect(events).toContain('complete');
    });

    it('should allow removing event listeners', () => {
      const timeline = new Timeline();
      const callback = vi.fn();

      timeline.on('start', callback);
      timeline.off('start', callback);

      timeline.start();
      expect(callback).not.toHaveBeenCalled();

      timeline.stop();
    });
  });

  describe('debugging utilities', () => {
    it('should generate tree representation', () => {
      const parent = new Timeline({ name: 'Parent' });
      const child = new Timeline({ name: 'Child' });

      parent.add(100, 'parent-task', vi.fn());
      child.add(50, 'child-task', vi.fn());
      parent.addTimeline(200, child);

      const tree = parent.toTree();

      expect(tree).toContain('Parent');
      expect(tree).toContain('Child');
      expect(tree).toContain('parent-task');
      expect(tree).toContain('child-task');
    });

    it('should provide meaningful toString', () => {
      const timeline = new Timeline({ name: 'Test Timeline' });
      timeline.add(100, 'task', vi.fn());

      const str = timeline.toString();

      expect(str).toContain('Test Timeline');
      expect(str).toContain('1 events');
      expect(str).toContain('idle');
    });
  });
});

