import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { Scheduler } from '../src/Scheduler.js';
import { Task, TaskState } from '../src/Task.js';
import { TaskPriority } from '../src/TaskPriority.js';
import { Timeline } from '../src/Timeline.js';

// Mock PrecisionClock
vi.mock('@psyforge/timing', () => ({
  PrecisionClock: class MockPrecisionClock {
    now() {
      return performance.now();
    }
  }
}));

describe('Scheduler', () => {
  let scheduler: Scheduler;

  beforeEach(() => {
    vi.useFakeTimers();
    scheduler = new Scheduler();
  });

  afterEach(() => {
    scheduler.stop();
    vi.restoreAllTimers();
  });

  describe('constructor', () => {
    it('should create scheduler with default options', () => {
      expect(scheduler.isRunning).toBe(false);
      expect(scheduler.queueLength).toBe(0);
      expect(scheduler.runningTaskCount).toBe(0);
    });

    it('should accept custom options', () => {
      const customScheduler = new Scheduler({
        maxTasksPerFrame: 5,
        frameTimeBudget: 16,
        timingTolerance: 1,
        allowPreemption: false
      });

      expect(customScheduler.isRunning).toBe(false);
    });
  });

  describe('lifecycle', () => {
    it('should start and stop correctly', () => {
      expect(scheduler.isRunning).toBe(false);

      scheduler.start();
      expect(scheduler.isRunning).toBe(true);

      scheduler.stop();
      expect(scheduler.isRunning).toBe(false);
    });

    it('should handle multiple start calls', () => {
      scheduler.start();
      expect(scheduler.isRunning).toBe(true);

      scheduler.start(); // Should not throw
      expect(scheduler.isRunning).toBe(true);
    });

    it('should handle stop when not running', () => {
      expect(scheduler.isRunning).toBe(false);

      scheduler.stop(); // Should not throw
      expect(scheduler.isRunning).toBe(false);
    });
  });

  describe('task scheduling', () => {
    beforeEach(() => {
      scheduler.start();
    });

    it('should schedule tasks at specific times', () => {
      const task = new Task('test-task', vi.fn());
      const executeAt = performance.now() + 1000;

      scheduler.scheduleTask(task, executeAt);

      expect(scheduler.queueLength).toBe(1);
    });

    it('should schedule delayed tasks', () => {
      const task = new Task('delayed-task', vi.fn());

      scheduler.scheduleDelayed(task, 500);

      expect(scheduler.queueLength).toBe(1);
    });

    it('should schedule next frame tasks', () => {
      const task = new Task('next-frame-task', vi.fn());

      scheduler.scheduleNextFrame(task);

      expect(scheduler.queueLength).toBe(1);
    });

    it('should not allow scheduling when stopped', () => {
      scheduler.stop();
      const task = new Task('test-task', vi.fn());

      expect(() => scheduler.scheduleTask(task, performance.now())).toThrow('Scheduler is not running');
    });
  });

  describe('task execution', () => {
    beforeEach(() => {
      scheduler.start();
    });

    it('should execute tasks at scheduled times', async () => {
      const executions: string[] = [];
      const task = new Task('test-task', () => {
        executions.push('executed');
      });

      scheduler.scheduleDelayed(task, 100);

      // Advance time and trigger frame
      vi.advanceTimersByTime(120);
      await vi.waitFor(() => expect(executions).toContain('executed'));

      expect(task.state).toBe(TaskState.COMPLETED);
    });

    it('should execute tasks in priority order', async () => {
      const executions: string[] = [];

      const lowPriorityTask = new Task('low', () => executions.push('low'), {
        priority: TaskPriority.NORMAL
      });
      const highPriorityTask = new Task('high', () => executions.push('high'), {
        priority: TaskPriority.CRITICAL
      });

      const executeTime = performance.now() + 100;
      scheduler.scheduleTask(lowPriorityTask, executeTime);
      scheduler.scheduleTask(highPriorityTask, executeTime);

      vi.advanceTimersByTime(120);
      await vi.waitFor(() => expect(executions).toHaveLength(2));

      expect(executions).toEqual(['high', 'low']);
    });

    it('should handle task execution errors', async () => {
      const error = new Error('Task failed');
      const task = new Task('failing-task', () => {
        throw error;
      });

      scheduler.scheduleDelayed(task, 100);

      vi.advanceTimersByTime(120);
      await vi.waitFor(() => expect(task.state).toBe(TaskState.FAILED));

      expect(task.error).toBe(error);
    });

    it('should respect frame budget', async () => {
      const scheduler = new Scheduler({ maxTasksPerFrame: 2 });
      scheduler.start();

      const executions: number[] = [];
      for (let i = 0; i < 5; i++) {
        const task = new Task(`task-${i}`, () => executions.push(i));
        scheduler.scheduleDelayed(task, 100);
      }

      // First frame should execute only 2 tasks
      vi.advanceTimersByTime(120);
      await vi.waitFor(() => expect(executions.length).toBeGreaterThan(0));

      // Should not execute all tasks in one frame
      expect(executions.length).toBeLessThanOrEqual(2);
    });
  });

  describe('task cancellation', () => {
    beforeEach(() => {
      scheduler.start();
    });

    it('should cancel queued tasks', () => {
      const task = new Task('test-task', vi.fn());
      scheduler.scheduleDelayed(task, 1000);

      const cancelled = scheduler.cancelTask(task);

      expect(cancelled).toBe(true);
      expect(task.state).toBe(TaskState.CANCELLED);
      expect(scheduler.queueLength).toBe(0);
    });

    it('should cancel running tasks', async () => {
      let resolveTask: () => void;
      const task = new Task('running-task', async () => {
        await new Promise<void>(resolve => {
          resolveTask = resolve;
        });
      });

      scheduler.scheduleDelayed(task, 100);

      vi.advanceTimersByTime(120);
      await vi.waitFor(() => expect(task.state).toBe(TaskState.RUNNING));

      const cancelled = scheduler.cancelTask(task);

      expect(cancelled).toBe(true);
      expect(task.state).toBe(TaskState.CANCELLED);

      // Clean up
      resolveTask!();
    });

    it('should not cancel already completed tasks', async () => {
      const task = new Task('completed-task', vi.fn());
      scheduler.scheduleDelayed(task, 100);

      vi.advanceTimersByTime(120);
      await vi.waitFor(() => expect(task.state).toBe(TaskState.COMPLETED));

      const cancelled = scheduler.cancelTask(task);

      expect(cancelled).toBe(false);
      expect(task.state).toBe(TaskState.COMPLETED);
    });

    it('should clear entire queue', () => {
      const tasks = [
        new Task('task1', vi.fn()),
        new Task('task2', vi.fn()),
        new Task('task3', vi.fn())
      ];

      tasks.forEach((task, i) => {
        scheduler.scheduleDelayed(task, i * 100);
      });

      expect(scheduler.queueLength).toBe(3);

      scheduler.clearQueue();

      expect(scheduler.queueLength).toBe(0);
      tasks.forEach(task => {
        expect(task.state).toBe(TaskState.CANCELLED);
      });
    });
  });

  describe('timeline management', () => {
    beforeEach(() => {
      scheduler.start();
    });

    it('should add and start timelines', async () => {
      const timeline = new Timeline({ name: 'Test Timeline' });
      const executions: string[] = [];

      timeline.add(100, 'timeline-task', () => executions.push('executed'));

      scheduler.addTimeline(timeline);

      vi.advanceTimersByTime(200);
      await vi.waitFor(() => expect(executions).toContain('executed'));
    });

    it('should remove timelines', () => {
      const timeline = new Timeline({ name: 'Test Timeline' });

      scheduler.addTimeline(timeline);
      scheduler.removeTimeline(timeline);

      // Timeline should be stopped if it was running
      expect(timeline.state).not.toBe('running');
    });
  });

  describe('metrics tracking', () => {
    beforeEach(() => {
      scheduler.start();
    });

    it('should track execution metrics', async () => {
      const task = new Task('test-task', vi.fn());
      scheduler.scheduleDelayed(task, 100);

      vi.advanceTimersByTime(120);
      await vi.waitFor(() => expect(task.state).toBe(TaskState.COMPLETED));

      const metrics = scheduler.metrics;
      expect(metrics.tasksExecuted).toBe(1);
      expect(metrics.queueLength).toBe(0);
    });

    it('should track timing errors', async () => {
      const task = new Task('late-task', vi.fn());
      // Schedule task but execute it late
      scheduler.scheduleTask(task, performance.now() - 10); // 10ms in the past

      vi.advanceTimersByTime(50);
      await vi.waitFor(() => expect(task.state).toBe(TaskState.COMPLETED));

      const metrics = scheduler.metrics;
      expect(metrics.lateExecutions).toBeGreaterThan(0);
      expect(metrics.averageTimingError).toBeGreaterThan(0);
    });

    it('should reset metrics', () => {
      scheduler.resetMetrics();

      const metrics = scheduler.metrics;
      expect(metrics.tasksExecuted).toBe(0);
      expect(metrics.lateExecutions).toBe(0);
      expect(metrics.averageTimingError).toBe(0);
      expect(metrics.maxTimingError).toBe(0);
    });
  });

  describe('query methods', () => {
    beforeEach(() => {
      scheduler.start();
    });

    it('should get scheduled tasks in time range', () => {
      const task1 = new Task('task1', vi.fn());
      const task2 = new Task('task2', vi.fn());
      const task3 = new Task('task3', vi.fn());

      const baseTime = performance.now();
      scheduler.scheduleTask(task1, baseTime + 100);
      scheduler.scheduleTask(task2, baseTime + 200);
      scheduler.scheduleTask(task3, baseTime + 300);

      const tasksInRange = scheduler.getScheduledTasks(baseTime + 150, baseTime + 250);

      expect(tasksInRange).toHaveLength(1);
      expect(tasksInRange[0]!.task).toBe(task2);
    });
  });

  describe('stop behavior', () => {
    it('should cancel all running tasks on stop', async () => {
      scheduler.start();

      let resolveTask: () => void;
      const task = new Task('long-running', async () => {
        await new Promise<void>(resolve => {
          resolveTask = resolve;
        });
      });

      scheduler.scheduleDelayed(task, 100);

      vi.advanceTimersByTime(120);
      await vi.waitFor(() => expect(task.state).toBe(TaskState.RUNNING));

      scheduler.stop();

      expect(task.state).toBe(TaskState.CANCELLED);

      // Clean up
      resolveTask!();
    });
  });

  describe('string representation', () => {
    it('should provide meaningful toString', () => {
      const str = scheduler.toString();

      expect(str).toContain('Scheduler');
      expect(str).toContain('running: false');
      expect(str).toContain('queue: 0');
      expect(str).toContain('running: 0');
    });
  });
});

