import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { 
  createScheduler, 
  createTimeline, 
  createTrialTimeline,
  createStimulusTask,
  createResponseTask,
  TaskPriority 
} from '../src/index.js';

describe('Scheduler Integration', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it('should run a complete experiment with hierarchical timelines', async () => {
    const scheduler = createScheduler();
    const experiment = createTimeline('Stroop Experiment');
    const trials = createTrialTimeline('Stroop Trials', 3, 1000);

    const executions: string[] = [];

    // Create experimental tasks
    const showStimulus = createStimulusTask('Show Word', () => {
      executions.push('stimulus');
    });

    const collectResponse = createResponseTask('Get Response', () => {
      executions.push('response');
    }, 2000);

    // Add tasks to trial timeline
    trials.addTask(0, showStimulus);
    trials.addTask(100, collectResponse);

    // Add trials to experiment
    experiment.addTimeline(500, trials);

    // Start scheduler and experiment
    scheduler.start();
    scheduler.addTimeline(experiment);

    // Verify initial state
    expect(scheduler.isRunning).toBe(true);
    expect(experiment.state).toBe('idle');

    // Advance time to start experiment
    vi.advanceTimersByTime(600);

    // Should start running
    await vi.waitFor(() => {
      return trials.state === 'running' || trials.state === 'completed';
    }, { timeout: 1000 });

    // Continue advancing time for multiple trials
    vi.advanceTimersByTime(5000);

    // Should have executed stimulus and response for each trial
    await vi.waitFor(() => {
      return executions.length >= 6; // 3 trials × 2 tasks
    }, { timeout: 1000 });

    expect(executions.filter(e => e === 'stimulus')).toHaveLength(3);
    expect(executions.filter(e => e === 'response')).toHaveLength(3);

    scheduler.stop();
  });

  it('should respect task priorities', async () => {
    const scheduler = createScheduler();
    const timeline = createTimeline('Priority Test');

    const executions: string[] = [];

    // Add tasks with different priorities at the same time
    timeline.add(100, 'low-priority', () => executions.push('low'), {
      priority: TaskPriority.NORMAL
    });

    timeline.add(100, 'high-priority', () => executions.push('high'), {
      priority: TaskPriority.CRITICAL
    });

    timeline.add(100, 'medium-priority', () => executions.push('medium'), {
      priority: TaskPriority.HIGH
    });

    scheduler.start();
    scheduler.addTimeline(timeline);

    vi.advanceTimersByTime(200);

    await vi.waitFor(() => {
      return executions.length >= 3;
    }, { timeout: 1000 });

    // Should execute in priority order: critical, high, normal
    expect(executions).toEqual(['high', 'medium', 'low']);

    scheduler.stop();
  });

  it('should handle nested timelines correctly', async () => {
    const scheduler = createScheduler();
    const experiment = createTimeline('Main Experiment');
    const block1 = createTimeline('Block 1');
    const block2 = createTimeline('Block 2');

    const executions: string[] = [];

    // Add tasks to blocks
    block1.add(50, 'block1-task', () => executions.push('block1'));
    block2.add(50, 'block2-task', () => executions.push('block2'));

    // Add blocks to experiment at different times
    experiment.addTimeline(100, block1);
    experiment.addTimeline(300, block2);

    scheduler.start();
    scheduler.addTimeline(experiment);

    vi.advanceTimersByTime(500);

    await vi.waitFor(() => {
      return executions.length >= 2;
    }, { timeout: 1000 });

    expect(executions).toEqual(['block1', 'block2']);

    // Verify hierarchy
    expect(block1.parent).toBe(experiment);
    expect(block2.parent).toBe(experiment);
    expect(experiment.children).toContain(block1);
    expect(experiment.children).toContain(block2);

    scheduler.stop();
  });

  it('should provide accurate timing metrics', async () => {
    const scheduler = createScheduler();
    const timeline = createTimeline('Metrics Test');

    // Add some tasks
    timeline.add(100, 'task1', () => {});
    timeline.add(200, 'task2', () => {});
    timeline.add(300, 'task3', () => {});

    scheduler.start();
    const initialMetrics = scheduler.metrics;
    expect(initialMetrics.tasksExecuted).toBe(0);

    scheduler.addTimeline(timeline);
    vi.advanceTimersByTime(400);

    await vi.waitFor(() => {
      return scheduler.metrics.tasksExecuted >= 3;
    }, { timeout: 1000 });

    const finalMetrics = scheduler.metrics;
    expect(finalMetrics.tasksExecuted).toBe(3);
    expect(finalMetrics.queueLength).toBe(0);

    scheduler.stop();
  });
});

